using Microsoft.EntityFrameworkCore;using Microsoft.EntityFrameworkCore.Metadata.Builders;using NutriCasa.Domain.Entities;
namespace NutriCasa.Infrastructure.Persistence.Configurations;
public class PostReactionConfiguration : IEntityTypeConfiguration<PostReaction>{public void Configure(EntityTypeBuilder<PostReaction> builder){builder.ToTable("post_reactions");builder.HasKey(e => e.Id);builder.Property(e => e.Id).HasColumnName("reaction_id").HasDefaultValueSql("uuid_generate_v4()");builder.Property(e => e.ReactionType).HasConversion<string>().HasMaxLength(20);builder.HasOne(e => e.Post).WithMany(p => p.Reactions).HasForeignKey(e => e.PostId).OnDelete(DeleteBehavior.Cascade);builder.HasOne(e => e.User).WithMany().HasForeignKey(e => e.UserId).OnDelete(DeleteBehavior.Cascade);builder.HasIndex(e => new { e.PostId, e.UserId, e.ReactionType }).IsUnique();}}
